class DifferentialSync{constructor(){this.lastSync=0,this.syncInterval=3e4,this.localData={},this.pendingChanges={},this.isSyncing=!1,this.syncQueue=[]}init(){this.syncTimer=setInterval(()=>this.sync(),this.syncInterval),document.addEventListener("visibilitychange",()=>{document.hidden||this.sync()}),window.addEventListener("beforeunload",()=>{this.syncNow()}),console.log("[DifferentialSync] ✅ Initialized")}async sync(){if(!this.isSyncing){this.isSyncing=!0;try{const n=await gasRun("getChanges",this.lastSync);if(!n||0===Object.keys(n).length)return void(this.isSyncing=!1);this.mergeChanges(n),this.lastSync=Date.now(),window.dispatchEvent(new CustomEvent("dataSync",{detail:{changes:n,timestamp:this.lastSync}})),console.log("[DifferentialSync] Synced",Object.keys(n).length,"changes")}catch(n){console.warn("[DifferentialSync] Sync error:",n)}finally{this.isSyncing=!1,this.syncQueue.length>0&&this.syncQueue.shift()()}}}async syncNow(){return new Promise(n=>{this.isSyncing?this.syncQueue.push(n):this.sync().then(n)})}mergeChanges(n){Object.keys(n).forEach(e=>{null===n[e]?delete this.localData[e]:this.localData[e]=n[e]})}recordChange(n,e){this.pendingChanges[n]=e,this.localData[n]=e}getData(n){return this.localData[n]}getAllData(){return{...this.localData}}getPendingChanges(){return{...this.pendingChanges}}clearPendingChanges(){this.pendingChanges={}}getMetrics(){return{lastSync:this.lastSync,localDataSize:Object.keys(this.localData).length,pendingChanges:Object.keys(this.pendingChanges).length,isSyncing:this.isSyncing}}destroy(){this.syncTimer&&clearInterval(this.syncTimer)}}"undefined"!=typeof window&&(window.differentialSync=new DifferentialSync,window.differentialSync.init(),console.log("[DifferentialSync] ✅ Initialized"));